import{_ as a,o as t,c as o,ag as i}from"./chunks/framework.YaIgwL5o.js";const u=JSON.parse('{"title":"Code, LaTeX & Markdown","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/code-math.md","filePath":"tutorials/code-math.md"}'),l={name:"tutorials/code-math.md"};function r(d,e,n,s,c,p){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="code-latex-markdown" tabindex="-1">Code, LaTeX &amp; Markdown <a class="header-anchor" href="#code-latex-markdown" aria-label="Permalink to &quot;Code, LaTeX &amp; Markdown&quot;">​</a></h1><p>This tutorial covers code blocks, LaTeX/TikZ elements, and Markdown blocks.</p><h2 id="code-blocks" tabindex="-1">Code blocks <a class="header-anchor" href="#code-blocks" aria-label="Permalink to &quot;Code blocks&quot;">​</a></h2><ol><li>Click <strong>Code</strong> in the toolbar.</li><li>A code block element appears. Double-click it to open the code editor.</li><li>Select a language from the dropdown (Python, JavaScript, TypeScript, C++, etc.).</li><li>Write or paste your code. Syntax highlighting is applied automatically.</li><li>Click <strong>Apply</strong> to save.</li></ol><h3 id="example-output" tabindex="-1">Example output <a class="header-anchor" href="#example-output" aria-label="Permalink to &quot;Example output&quot;">​</a></h3><div style="border:1px solid #333;border-radius:8px;overflow:hidden;margin:16px 0;"><iframe src="/revealjs_gui/demos/code-block.html" style="width:100%;height:260px;border:none;"></iframe></div><h2 id="latex-tikz" tabindex="-1">LaTeX &amp; TikZ <a class="header-anchor" href="#latex-tikz" aria-label="Permalink to &quot;LaTeX &amp; TikZ&quot;">​</a></h2><ol><li>Click the <strong>TeX</strong> button in the toolbar.</li><li>A LaTeX element appears. Double-click it to open the LaTeX editor.</li><li>Enter LaTeX code — display math, aligned equations, or TikZ diagrams.</li><li>A live preview renders on the left as you type.</li><li>Click <strong>Apply</strong> to save.</li></ol><h3 id="example-output-1" tabindex="-1">Example output <a class="header-anchor" href="#example-output-1" aria-label="Permalink to &quot;Example output&quot;">​</a></h3><div style="border:1px solid #333;border-radius:8px;overflow:hidden;margin:16px 0;"><iframe src="/revealjs_gui/demos/latex-equation.html" style="width:100%;height:100px;border:none;"></iframe></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>For TikZ diagrams, the editor uses TikZJax for client-side rendering. Wrap your code in <code>\\begin{tikzpicture}...\\end{tikzpicture}</code>.</p></div><h2 id="markdown-blocks" tabindex="-1">Markdown blocks <a class="header-anchor" href="#markdown-blocks" aria-label="Permalink to &quot;Markdown blocks&quot;">​</a></h2><ol><li>Click the <strong>Markdown</strong> button in the toolbar (or find it under the insert menu).</li><li>A markdown element appears. Double-click it to edit.</li><li>Write standard Markdown — headings, lists, links, bold/italic, code blocks.</li><li>The rendered output appears when you deselect the element.</li></ol><p>Markdown blocks are useful for quickly inserting formatted text without manual styling.</p>',14)])])}const m=a(l,[["render",r]]);export{u as __pageData,m as default};
